from importlib.util import find_spec as fs
from importlib.metadata import distribution as dist, distributions as dists, version
from importlib.machinery import ModuleSpec
import ast, re
from ast import get_source_segment as gs
from codesigs import file_sigs
from fastcore.basics import true
from fastcore.nbio import read_nb

# %% ../nbs/02_data.ipynb #2d62e37b470a1055
skip_folder_re = r'^[._]|^(?:tests?|examples?|docs?|build|dist)$'
skip_file_re = r'^[._]|^(?:setup\.py|conftest\.py)$'
code_types = 'py,js,ts,jsx,tsx,java,go,cs,ruby,php,swift,kt,kts,rs,scala,lua'
file_types = code_types + ',md,txt,pdf,ipynb'

def repo_root() -> Path:
	'Find the root of the current git repository, or None if not in a repo.'
	return first((Path.cwd(), *Path.cwd().parents), lambda p: (p/'.git').exists())

def spec(pkg:str) -> ModuleSpec | None:
	'Return the importlib ModuleSpec for a package, or None if not found.'
	try: return fs(pkg) or fs(pkg.replace('-', '_')) or fs(dist(pkg).read_text('top_level.txt').splitlines()[0])
	except ModuleNotFoundError: return None

def pyparse(p:Path=None,    # path to a python file
            code:str=None,  # code string to parse
            imports=False,   # include import statements as code chunks
            assigns=False       # include top-level assignments as code chunks
) -> L:
    'Parse a code string or python file and return code chunks as list of dicts with content and metadata.'
    assert bool(code) ^ bool(p), 'Either code or p must be provided, not both.'
    try: code = Path(p).read_text(encoding='utf-8') if not code else code
    except UnicodeDecodeError: return L()
    tree=ast.parse(code)
    [setattr(c,'parent',n) for n in ast.walk(tree) for c in ast.iter_child_nodes(n)]
    def meta(xtra=None): return dict(path=p,uploaded_at=Path(p).stat().st_mtime if p else None,**ifnone(xtra, {}))
    def n2c(n):
	    return dict(content=gs(code, n).strip(), metadata=meta(dict(name=getattr(n,'name',None),lang='.py',
            type=type2str(n.__class__), lineno=getattr(n,'lineno',None), end_lineno=getattr(n,'end_lineno',None))))
    def is_mod(n): return isinstance(n, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef))
    def is_assign(n): return assigns and isinstance(n, (ast.Assign, ast.AnnAssign)) and n.value
    def is_p_mod(n): return getattr(getattr(n,'parent',None),'__class__',None) == ast.Module
    def is_allowed(n): return is_p_mod(n) and (is_mod(n) or is_assign(n) or (imports and isinstance(n, ast.ImportFrom)))
    return L(ast.walk(tree)).filter(is_allowed).map(n2c)

def ipynb_parse(p):
	'Parse ipynb files'
	def meta_(): return dict(path=p, uploaded_at=Path(p).stat().st_mtime, lang=p.suffix)
	fn = lambda c: dict(content=c['source'], metadata = meta_() | dict(type=c['cell_type']))
	return L(read_nb(p).cells).map(fn)

def non_py_sigs(p):
	'Signatures for paths that are not python code files using codesigs'
	def meta_(): return dict(path=p, uploaded_at=Path(p).stat().st_mtime, lang=p.suffix)
	return L(file_sigs(p)).map(lambda o: dict(content=o, metadata=meta_()))

def chunk_texts(text:str):
	'Chunk texts using Fast Chunker'
	from chonkie import FastChunker
	return L(FastChunker(delimiters='\n\n')(text)).map(lambda c: c.text)

@delegates(pyparse)
def file_parse(p:Path=None,  # path to a code file
               **kwargs      # additional args to pass to pyparse
               ) -> L:
    'Parse a code file or code string and return code chunks with metadata.'
    if p.suffix == '.py': return pyparse(p, **kwargs)
    if p.suffix == '.ipynb': return ipynb_parse(p)
    if p.suffix[1:] in code_types.split(','): return non_py_sigs(p)
    def meta_(): return dict(path=p, uploaded_at=Path(p).stat().st_mtime, lang=p.suffix)
    if p.suffix == '.pdf': return PdfDocument(p).pdf_chunks().map(lambda c: dict(content=c[2], metadata=meta_()))
    fn = lambda c: dict(content=c,metadata=meta_())
    if p.suffix  == '.md': return chunk_markdown(p.read_text(encoding='utf-8')).map(fn)
    if p.suffix == '.txt': return chunk_texts(p.read_text(encoding='utf-8')).map(fn)
    return L()

