def img2png(img) -> bytes:
    'Normalise image input (PIL Image / bytes / path) to PNG bytes as RGB.'
    from PIL import Image
    import io
    if isinstance(img, (str, Path)): img = Image.open(img)
    elif isinstance(img, (bytes, bytearray)): img = Image.open(io.BytesIO(img))
    buf = io.BytesIO()
    img.convert('RGB').save(buf, format='PNG')
    return buf.getvalue()

def png_det(png: bytes):
    'Return (width, height, concatenated IDAT bytes) from a PNG.'
    w = _struct.unpack('>I', png[16:20])[0]
    h = _struct.unpack('>I', png[20:24])[0]
    idat, i = bytearray(), 8
    while i < len(png):
        ln = _struct.unpack('>I', png[i:i+4])[0]
        if png[i+4:i+8] == b'IDAT': idat.extend(png[i+8:i+8+ln])
        elif png[i+4:i+8] == b'IEND': break
        i += 12 + ln
    return w, h, bytes(idat)

def images_to_pdf(imgs,       # list of PIL Images, bytes, or file paths
                  output=None # path to save, or None to return bytes
) -> bytes:
    'Convert a list of images into a multi-page image-only PDF (one image per page).'
    pages = [png_det(img2png(img)) for img in imgs]
    N = len(pages)
    kids = ' '.join(f'{3+i*3} 0 R' for i in range(N))
    o = {
        1: b'<</Type /Catalog /Pages 2 0 R>>',
        2: f'<</Type /Pages /Kids [{kids}] /Count {N}>>'.encode(),
    }
    for i, (w, h, idat) in enumerate(pages):
        b = 3 + i * 3
        cm = f'q {w} 0 0 {h} 0 0 cm /Im1 Do Q'.encode()
        o[b]   = f'<</Type /Page /Parent 2 0 R /MediaBox [0 0 {w} {h}] /Contents {b+1} 0 R /Resources <</XObject <</Im1 {b+2} 0 R>>>>>>'.encode()
        o[b+1] = f'<</Length {len(cm)}>>'.encode() + b'\nstream\n' + cm + b'\nendstream'
        o[b+2] = (f'<</Type /XObject /Subtype /Image /Width {w} /Height {h} /ColorSpace /DeviceRGB '
                  f'/BitsPerComponent 8 /Filter /FlateDecode '
                  f'/DecodeParms <</Predictor 15 /Colors 3 /BitsPerComponent 8 /Columns {w}>> '
                  f'/Length {len(idat)}>>').encode() + b'\nstream\n' + idat + b'\nendstream'
    out, offs = b'%PDF-1.7\n', {}
    for n in sorted(o): offs[n] = len(out); out += f'{n} 0 obj\n'.encode() + o[n] + b'\nendobj\n'
    xp = len(out)
    out += (b'xref\n' + f'0 {len(o)+1}\n'.encode() + b'0000000000 65535 f \n'
            + b''.join(f'{offs[n]:010d} 00000 n \n'.encode() for n in sorted(o))
            + f'trailer\n<</Size {len(o)+1} /Root 1 0 R>>\nstartxref\n{xp}\n%%EOF\n'.encode())
    if output: open(output, 'wb').write(out)
    return out
